# Category: edge_computing_security

import json
import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    # Check if the X-Enrich-URL header is present
    enrich_url = headers.get('x-enrich-url')

    if enrich_url:
        # Extract the URL from the header value
        enrich_url = enrich_url[0]['value']

        # Send HTTP request to the enrichment URL
        response = requests.get(enrich_url)

        # Parse the response as JSON
        context_data = json.loads(response.content)

        # Add the context data to the request context
        request['context']['enrichment'] = context_data

    return request